(function(global){'use strict';var TableComponent={enableResize:function(table){if(!table||table._resizeEnabled)return;table._resizeEnabled=true;var ths=table.querySelectorAll('th');ths.forEach(function(th,index){var handle=document.createElement('div');handle.className='col-resize-handle';th.appendChild(handle);var startX,startWidth,nextWidth;function onMouseDown(e){e.preventDefault();e.stopPropagation();startX=e.clientX;startWidth=th.offsetWidth;var nextTh=th.nextElementSibling;nextWidth=nextTh ? nextTh.offsetWidth:0;document.addEventListener('mousemove',onMouseMove);document.addEventListener('mouseup',onMouseUp);document.body.style.cursor='col-resize';document.body.style.userSelect='none';}function setColWidth(colIdx,width){var newW=Math.max(30,width);var rows=table.querySelectorAll('tr');rows.forEach(function(row){var cell=row.children[colIdx];if(cell){cell.style.width=newW+'px';cell.style.minWidth=newW+'px';cell.style.maxWidth=newW+'px';}});}function onMouseMove(e){var diff=e.clientX-startX;var newWidth=Math.max(40,startWidth+diff+0.5|0);var minNext=30;if(ths[index+1]){var newNext=nextWidth-diff;if(newNext<minNext){newWidth=startWidth+(nextWidth-minNext);}setColWidth(index+1,Math.max(minNext,newNext));}setColWidth(index,newWidth);}function onMouseUp(){document.removeEventListener('mousemove',onMouseMove);document.removeEventListener('mouseup',onMouseUp);document.body.style.cursor='';document.body.style.userSelect='';}handle.addEventListener('mousedown',onMouseDown);});},init:function(table){if(!table)return;this.enableResize(table);},autoInit:function(){var self=this;var containers=document.querySelectorAll('.data-table');containers.forEach(function(container){var table=container.querySelector('table');if(table)self.init(table);});}};global.TableComponent=TableComponent;if(document.readyState==='loading'){document.addEventListener('DOMContentLoaded',function(){TableComponent.autoInit();});}else{TableComponent.autoInit();}})(window);